#include <iostream>
#include <fstream>
#include <string>
#include <vector>
#include <cstdio> // For remove()

// This function simulates running the student's compiled program.
// It assumes the student's code has been compiled into an executable named 'solution'.
std::string run_student_code(const std::string& input_str) {
    const std::string input_filename = "temp_input.txt";
    const std::string output_filename = "temp_output.txt";

    // Write the input string to a temporary file
    std::ofstream input_file(input_filename);
    if (!input_file.is_open()) {
        return "ERROR: Could not create input file.\n";
    }
    input_file << input_str;
    input_file.close();

    // Execute the student's program, redirecting stdin from temp_input.txt
    // and stdout to temp_output.txt
    std::string command = "./solution < " + input_filename + " > " + output_filename;
    int system_result = system(command.c_str());

    // Read the output from the temporary output file
    std::ifstream output_file(output_filename);
    if (!output_file.is_open()) {
        return "ERROR: Could not open output file.\n";
    }
    std::string program_output;
    std::string line;
    while (std::getline(output_file, line)) {
        program_output += line + "\n";
    }
    output_file.close();

    // Clean up temporary files
    std::remove(input_filename.c_str());
    std::remove(output_filename.c_str());

    // Check if the program execution itself failed (e.g., crash)
    if (system_result != 0) {
        return "ERROR: Program exited with non-zero status. Output:\n" + program_output;
    }

    return program_output;
}

int main() {
    // This main function would typically iterate through test cases
    // and call run_student_code for each.
    // The actual test cases are defined in the JSON structure.
    // This driver code is just the utility function for execution.
    // The external testing framework would use this `run_student_code` function.
    std::cout << "Driver ready to run student code." << std::endl;
    return 0;
}
